// // This module implements a 64-bit wide, 2-to-1 demultiplexer. When the flag input is set to 1, the output selects the value from in2; otherwise, it selects the value from in1.
module top_module(in1,in2,flag,out);input [0:63]in1,in2;
    input flag;
    output [0:63]out;
    assign out=(flag==1'b1)?in1:in2;
endmodule
